sql:
SELECT COUNT(book_id) AS number_of_recommended_books
FROM recommended_books
WHERE user_id = 1;

SELECT MAX(total_books) AS max_books_in_genre
FROM (
    SELECT COUNT(book_id) AS total_books
    FROM books
    GROUP BY genre_id
);

SELECT AVG(T3.rating) AS average_rating
FROM recommended_books T1
JOIN user_book_history T3 ON T1.user_id = T3.user_id;
